// Trong MusicContext.js
useEffect(() => {
  if (currentSong && isPlaying) {
    // Đảm bảo audio đã load nguồn mới trước khi phát
    audioRef.current.play().catch(err => {
      console.log("Chờ người dùng tương tác hoặc lỗi nạp nhạc:", err);
    });
  }
}, [currentSong, isPlaying]); // Chạy mỗi khi đổi bài HOẶC đổi trạng thái play/pause

const playMusic = (songsList, index) => {
  setSongs(songsList);
  setCurrentIndex(index);
  setCurrentSong(songsList[index]);
  setIsPlaying(true); // Gán luôn là true
};
